from __future__ import annotations
from dataclasses import dataclass, field
from enum import Enum
from typing import Optional


class MobRole(Enum):
    DRIVER           = "driver"
    TOOL_SCHEMA_NAV  = "tool_schema_nav"
    SAFETY_NAV       = "safety_nav"
    TRACE_ANALYST    = "trace_analyst"
    EVAL_KEEPER      = "eval_keeper"


@dataclass
class MobMember:
    name: str
    role: MobRole


class RotationResult(Enum):
    CONTINUE   = "continue"   # eval passed; proceed to next rotation
    ROLLBACK   = "rollback"   # eval regressed > 5pp; revert last change
    SAFETY_HALT = "safety_halt"  # safety navigator called a halt


@dataclass
class MobIteration:
    iteration_number: int
    driver: MobMember
    change_description: str
    eval_pass_rate_before: float
    eval_pass_rate_after: float
    trace_issues: list[str] = field(default_factory=list)     # from trace analyst
    safety_flags: list[str] = field(default_factory=list)     # from safety nav
    schema_flags: list[str] = field(default_factory=list)     # from schema nav
    result: RotationResult = RotationResult.CONTINUE

    @property
    def eval_delta(self) -> float:
        return self.eval_pass_rate_after - self.eval_pass_rate_before

    @property
    def is_regression(self) -> bool:
        return self.eval_delta < -0.05   # 5pp regression threshold

    def determine_result(self) -> RotationResult:
        if self.safety_flags:
            return RotationResult.SAFETY_HALT
        if self.is_regression:
            return RotationResult.ROLLBACK
        return RotationResult.CONTINUE


@dataclass
class MobSession:
    feature_id: str
    agent_name: str
    members: list[MobMember]
    iterations: list[MobIteration] = field(default_factory=list)
    rotation_minutes: int = 15    # driver rotates every 15 minutes

    def current_driver(self) -> Optional[MobMember]:
        drivers = [m for m in self.members if m.role == MobRole.DRIVER]
        return drivers[0] if drivers else None

    def rotate_driver(self) -> None:
        """Move current driver to EVAL_KEEPER; next person becomes DRIVER."""        # Simplest round-robin: rotate the roles list one position
        roles = [m.role for m in self.members]
        roles = roles[-1:] + roles[:-1]
        for member, role in zip(self.members, roles):
            member.role = role

    def safety_halt_count(self) -> int:
        return sum(1 for i in self.iterations if i.result == RotationResult.SAFETY_HALT)

    def rollback_count(self) -> int:
        return sum(1 for i in self.iterations if i.result == RotationResult.ROLLBACK)

    def final_eval_rate(self) -> float:
        if not self.iterations:
            return 0.0
        # Use last CONTINUE or ROLLBACK result (post-rollback, rate returns to pre)
        return self.iterations[-1].eval_pass_rate_after

    def summary(self) -> dict:
        return {
            "feature_id": self.feature_id,
            "agent": self.agent_name,
            "iterations": len(self.iterations),
            "safety_halts": self.safety_halt_count(),
            "rollbacks": self.rollback_count(),
            "final_eval_rate": self.final_eval_rate(),
            "total_trace_issues": sum(len(i.trace_issues) for i in self.iterations),
            "total_schema_flags": sum(len(i.schema_flags) for i in self.iterations),
        }

from typing import Any


@dataclass
class ToolSchemaReview:
    tool_name: str
    schema: dict[str, Any]
    issues: list[str] = field(default_factory=list)

    def review(self) -> list[str]:
        """Returns a list of schema issues. Empty list means schema passes."""        issues: list[str] = []
        props = self.schema.get("parameters", {}).get("properties", {})
        required = self.schema.get("parameters", {}).get("required", [])

        # 1. Check for over-permission: action tools should have explicit scope
        action_keywords = {"write", "delete", "send", "execute", "run", "post", "create"}
        if any(kw in self.tool_name.lower() for kw in action_keywords):
            if not any("scope" in k or "limit" in k or "dry_run" in k for k in props):
                issues.append(
                    f"{self.tool_name}: action tool missing scope/dry_run parameter. "                    "Add a dry_run:bool flag or scope enum to limit blast radius."
                )

        # 2. Check for ambiguous string arguments (should use enum where possible)
        for field_name, field_schema in props.items():
            if field_schema.get("type") == "string" and "enum" not in field_schema:
                if any(kw in field_name.lower() for kw in {"action", "mode", "type", "operation"}):
                    issues.append(
                        f"{self.tool_name}.{field_name}: string type on a control argument. "                        "Consider using enum to prevent model hallucinating an invalid value."
                    )

        # 3. Check that all required fields have descriptions
        for field_name in required:
            field_schema = props.get(field_name, {})
            if "description" not in field_schema:
                issues.append(
                    f"{self.tool_name}.{field_name}: required field missing 'description'. "                    "Model relies on description to know when and how to fill each argument."
                )

        self.issues = issues
        return issues


# Example: a risky tool schema that the navigator should catch
risky_schema = {
    "name": "execute_database_query",
    "description": "Runs a SQL query against the production database.",
    "parameters": {
        "type": "object",
        "properties": {
            "query": {"type": "string"},     # no description — navigator flags this
            "operation": {"type": "string"}, # should be enum(SELECT|INSERT|UPDATE|DELETE)
        },
        "required": ["query", "operation"],
    },
}
review = ToolSchemaReview(tool_name="execute_database_query", schema=risky_schema)
print(review.review())
